import { getUser, getSignInUrl, getSignUpUrl } from '@workos-inc/authkit-nextjs';
import Link from 'next/link';

export default async function HomePage() {
  const { user } = await getUser();
  const signInUrl = await getSignInUrl();
  const signUpUrl = await getSignUpUrl();

  return (
    <div className="flex flex-col items-center justify-center min-h-screen py-2">
      <h1 className="text-6xl font-bold">WorkOS AuthKit + Next.js</h1>
      <p className="mt-4 text-2xl">
        The easiest way to add authentication to your Next.js app.
      </p>

      <div className="mt-8 flex gap-4">
        {user ? (
          <>
            <p>Signed in as {user.email}</p>
            <Link
              href="/dashboard"
              className="px-6 py-3 bg-blue-600 text-white rounded-lg font-semibold hover:bg-blue-700"
            >
              Go to Dashboard
            </Link>
          </>
        ) : (
          <>
            <Link
              href={signInUrl}
              className="px-6 py-3 bg-blue-600 text-white rounded-lg font-semibold hover:bg-blue-700"
            >
              Sign In
            </Link>
            <Link
              href={signUpUrl}
              className="px-6 py-3 bg-gray-200 text-gray-800 rounded-lg font-semibold hover:bg-gray-300"
            >
              Sign Up
            </Link>
          </>
        )}
      </div>
    </div>
  );
}

